module top_module(A, B, result);input [3:0] A;
    input [3:0] B;
    output reg [7:0] result; // changed to reg to hold the value in always block

    reg [7:0] temp;
    reg [3:0] obf_i;

    always @* begin
        temp = 0;
        for (obf_i = 0; obf_i < 4; obf_i = obf_i+1) begin
            if (B[obf_i] == 1) begin
                temp = temp + (A << obf_i);
            end
        end
        result = temp; // result can now be assigned
    end
endmodule
